diff --git a/test/patch.test.ts b/test/patch.test.ts
new file mode 100644
index 0000000..ec88de3
--- /dev/null
+++ b/test/patch.test.ts
@@ -0,0 +1,28 @@
+import { test, beforeEach } from "node:test";
+import assert from "node:assert/strict";
+import { handle } from "../src/app.ts";
+import { reset } from "../src/store.ts";
+
+beforeEach(() => reset());
+
+test("PATCH /tasks/:id updates the task title", () => {
+  const created = handle({ method: "POST", path: "/tasks", body: { title: "buy milk" } }).body as { id: string; title: string };
+  assert.equal(created.title, "buy milk");
+
+  const res = handle({ method: "PATCH", path: `/tasks/${created.id}`, body: { title: "buy bread" } });
+  assert.equal(res.status, 200);
+  const updated = res.body as { id: string; title: string };
+  assert.equal(updated.title, "buy bread");
+  assert.equal(updated.id, created.id);
+});
+
+test("PATCH /tasks/:id returns 404 if task not found", () => {
+  const res = handle({ method: "PATCH", path: "/tasks/nope", body: { title: "test" } });
+  assert.equal(res.status, 404);
+});
+
+test("PATCH /tasks/:id rejects an empty title with 400", () => {
+  const created = handle({ method: "POST", path: "/tasks", body: { title: "buy milk" } }).body as { id: string };
+  assert.equal(handle({ method: "PATCH", path: `/tasks/${created.id}`, body: { title: "  " } }).status, 400);
+  assert.equal(handle({ method: "PATCH", path: `/tasks/${created.id}`, body: {} }).status, 400);
+});

